import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline
import math

# Define optimized fused kernel with better memory access patterns
fused_kernel_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cmath>

constexpr float GELU_COEF = 0.044715f;
constexpr float SQRT_2_OVER_PI = 0.7978845608028654f;
constexpr float NEGATIVE_SLOPE = 0.01f;

__device__ __forceinline__ float leaky_relu(float x) {
    return x > 0.0f ? x : x * NEGATIVE_SLOPE;
}

__device__ __forceinline__ float gelu(float x) {
    return 0.5f * x * (1.0f + tanhf(SQRT_2_OVER_PI * (x + GELU_COEF * x * x * x)));
}

__global__ void fused_gemm_logsumexp_leaky_gelu_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int batch_size,
    int in_features,
    int out_features,
    bool has_bias) {

    // Each thread block processes multiple batch elements for better occupancy
    const int elements_per_block = 4;
    const int block_start = blockIdx.x * elements_per_block;

    // Shared memory for intermediate results
    extern __shared__ float shared_mem[];
    float* gemm_results = shared_mem;

    // Process multiple batch elements per block
    for (int local_batch = 0; local_batch < elements_per_block; local_batch++) {
        int batch_idx = block_start + local_batch;
        if (batch_idx >= batch_size) break;

        const float* input_row = input + batch_idx * in_features;

        // Phase 1: Compute GEMM using warp-level parallelism
        for (int feat_idx = threadIdx.x; feat_idx < out_features; feat_idx += blockDim.x) {
            const float* weight_row = weight + feat_idx * in_features;

            float sum = 0.0f;
            // Unrolled for better performance
            #pragma unroll(8)
            for (int i = 0; i < in_features; i++) {
                sum += input_row[i] * weight_row[i];
            }

            if (has_bias) {
                sum += bias[feat_idx];
            }

            gemm_results[local_batch * out_features + feat_idx] = sum;
        }
        __syncthreads();

        // Phase 2: LogSumExp reduction using warp shuffle for efficiency
        if (threadIdx.x < 32) {  // Use first warp for reduction
            float thread_max = -INFINITY;
            float thread_sum = 0.0f;

            // Each thread in warp handles multiple elements
            for (int i = threadIdx.x; i < out_features; i += 32) {
                float val = gemm_results[local_batch * out_features + i];
                thread_max = fmaxf(thread_max, val);
            }

            // Warp reduction for max
            for (int offset = 16; offset > 0; offset >>= 1) {
                float other = __shfl_down_sync(0xffffffff, thread_max, offset);
                thread_max = fmaxf(thread_max, other);
            }

            float row_max = __shfl_sync(0xffffffff, thread_max, 0);

            // Compute sum of exp(values - max)
            for (int i = threadIdx.x; i < out_features; i += 32) {
                float val = gemm_results[local_batch * out_features + i];
                thread_sum += expf(val - row_max);
            }

            // Warp reduction for sum
            for (int offset = 16; offset > 0; offset >>= 1) {
                float other = __shfl_down_sync(0xffffffff, thread_sum, offset);
                thread_sum += other;
            }

            float total_sum = __shfl_sync(0xffffffff, thread_sum, 0);

            // Phase 3: Compute final activations
            if (threadIdx.x == 0) {
                float logsumexp_result = logf(total_sum) + row_max;

                // Apply activations in sequence
                float x = leaky_relu(logsumexp_result);
                x = leaky_relu(x);
                x = gelu(x);
                x = gelu(x);

                output[batch_idx] = x;
            }
        }
        __syncthreads();
    }
}

torch::Tensor fused_forward_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias) {

    auto batch_size = input.size(0);
    auto in_features = input.size(1);
    auto out_features = weight.size(0);

    auto output = torch::empty({batch_size, 1}, 
                               torch::TensorOptions().dtype(input.dtype()).device(input.device()));

    bool has_bias = bias.numel() > 0;

    // Optimized kernel configuration
    const int threads_per_block = 256;
    const int elements_per_block = 4;
    const int blocks_per_grid = (batch_size + elements_per_block - 1) / elements_per_block;

    // Shared memory: gemm_results for multiple batch elements
    size_t shared_mem_size = elements_per_block * out_features * sizeof(float);

    fused_gemm_logsumexp_leaky_gelu_kernel<<<blocks_per_grid, threads_per_block, shared_mem_size>>>(
        input.data_ptr<float>(),
        weight.data_ptr<float>(),
        has_bias ? bias.data_ptr<float>() : nullptr,
        output.data_ptr<float>(),
        batch_size,
        in_features,
        out_features,
        has_bias);

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }

    return output;
}
"""

fused_kernel_cpp_source = """
torch::Tensor fused_forward_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias);
"""

# Compile the fused CUDA kernel
fused_ops = load_inline(
    name="fused_ops",
    cpp_sources=fused_kernel_cpp_source,
    cuda_sources=fused_kernel_source,
    functions=["fused_forward_cuda"],
    verbose=False,
    extra_cflags=["-O3", "-ffast-math"],
    extra_ldflags=[""],
    with_cuda=True
)

class ModelNew(nn.Module):
    """
    Optimized model with fused CUDA kernel for Gemm + LogSumExp + LeakyReLU + GELU operations.
    """
    def __init__(self, in_features, out_features, bias=True):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features

        # Initialize weights and bias like nn.Linear
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        if bias:
            self.bias = nn.Parameter(torch.empty(out_features))
        else:
            self.register_parameter('bias', None)

        self.reset_parameters()
        self.fused_forward = fused_ops.fused_forward_cuda

    def reset_parameters(self):
        # Same initialization as nn.Linear
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x):
        # Single fused kernel call replacing all operations
        bias_tensor = self.bias if self.bias is not None else torch.empty(0, device=x.device, dtype=x.dtype)
        return self.fused_forward(x, self.weight, bias_tensor)

batch_size = 128
in_features = 1024
out_features = 512

def get_inputs():
    return [torch.randn(batch_size, in_features).cuda()]

def get_init_inputs():
    return [in_features, out_features]

